        }
        .history-item:hover { background: #1e1e20; }
        .history-title { font-size: 13px; font-weight: 500; color: #eee; }
        .history-date { font-size: 11px; color: #666; }

        /* Header Icons Gap */
        .chat-header .flex-gap .icon-btn { border: none; background: transparent; padding: 6px; }
        .chat-header .flex-gap .icon-btn:hover { background: rgba(255,255,255,0.1); }

        /* AI SETTINGS UI */
