        .ai-provider-card { background: #1a1a1c; border: 1px solid var(--border); border-radius: 8px; padding: 12px; margin-bottom: 10px; position: relative; }
        .ai-provider-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }
        .ai-tag { font-size: 9px; padding: 2px 6px; border-radius: 4px; background: #333; color: #aaa; text-transform: uppercase; }
        .ai-tag.openai { background: rgba(34, 197, 94, 0.1); color: #4ade80; }
        .ai-tag.google { background: rgba(59, 130, 246, 0.1); color: #60a5fa; }

        .role-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
        .role-card { background: #111; padding: 10px; border: 1px solid var(--border); border-radius: 8px; }
        .role-label { font-size: 11px; color: var(--text-muted); display: block; margin-bottom: 5px; }
        .role-select { width: 100%; background: #222; color: white; border: 1px solid #333; padding: 6px; border-radius: 4px; font-size: 12px; }

    </style>
