        if(typeof acorn === 'undefined') console.warn("Acorn missing. Syntax checking disabled.");

        // --- CONDUIT INSPECTOR BUS ---
    window.inspectorLogData = [];
    window.ideLogData = [];
    window.inspectorNetData = [];
    window.ideNetData = [];
    window.currentLogSource = 'app';

    // --- HOST IDE LOG & NET INTERCEPTOR ---
    const originalConsole = { ...console };
    ['log', 'warn', 'error', 'info', 'debug'].forEach(method => {
        console[method] = (...args) => {
            const msg = args.map(a => typeof a === 'object' ? JSON.stringify(a, null, 2) : String(a)).join(' ');
            const time = new Date().toLocaleTimeString([], {hour12:false, hour:'2-digit', minute:'2-digit', second:'2-digit'});
            window.ideLogData.push({ method, msg, time });

            const container = document.getElementById('ins-console-ide');
            if (container) renderLogLine(container, method, msg, time);
            originalConsole[method].apply(console, args);
        };
    });

    const originalFetch = window.fetch;
    window.fetch = async (...args) => {
        const start = Date.now();
        const url = args[0];
        const options = args[1] || {};
        try {
            const response = await originalFetch(...args);
            const clone = response.clone();
            const duration = Date.now() - start;
            let resBody = '[Binary Data]';
            try { resBody = await clone.json(); } catch(e) { try { resBody = await clone.text(); } catch(e2){} }

            const netEntry = {
                url, method: options.method || 'GET',
                status: response.status, duration,
                requestBody: options.body || null,
                responseBody: resBody
            };
            window.ideNetData.push(netEntry);
            renderNetworkRow('ide', netEntry);
            return response;
        } catch(err) { throw err; }
    };

    function renderLogLine(container, method, msg, time) {
        const row = document.createElement('div');
        row.className = `ins-row ins-log-${method}`;

        const isMultiline = msg.includes('\n') || msg.length > 120 || msg.includes('stack:');

        if (!isMultiline) {
            row.innerHTML = `<button class="ins-copy-btn" onclick="copyInsEntry(this)">Copy</button>` +
                            `<span style="color:#555; margin-right:10px; font-size:9px;">${time}</span>` +
                            `<span style="white-space:pre-wrap; word-break:break-all;">${escapeHtml(msg)}</span>`;
        } else {
            const lines = msg.split('\n');
            const firstLine = lines[0].substring(0, 100) + (lines[0].length > 100 ? '...' : '');

            row.innerHTML = `
                <button class="ins-copy-btn" onclick="copyInsEntry(this)">Copy</button>
                <details style="width:100%">
                    <summary style="cursor:pointer; outline:none; display:flex; align-items:flex-start; gap:8px;">
                        <span style="color:#555; font-size:9px; margin-top:2px;">${time}</span>
                        <span style="color:var(--text-muted); font-size:11px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;">${escapeHtml(firstLine)}</span>
                    </summary>
                    <div style="margin-top:8px; padding:10px; background:rgba(0,0,0,0.3); border-radius:6px; border:1px solid rgba(255,255,255,0.05); overflow-x:auto;">
                        <pre style="white-space:pre-wrap; word-break:break-all; font-family:'JetBrains Mono'; font-size:10px; color:#ccc; margin:0;">${escapeHtml(msg)}</pre>
                    </div>
                </details>`;
        }

        container.appendChild(row);
        if (container.scrollHeight - container.scrollTop < 1000) container.scrollTop = container.scrollHeight;
    }

        function renderNetworkRow(source, req) {
        const list = document.getElementById(`ins-net-${source}`);
        if (!list) return;
        const id = 'net-' + Date.now() + Math.random().toString(36).substr(2, 5);
        const row = document.createElement('div');
        row.className = 'ins-row';
        row.innerHTML = `
            <div class="ins-net-grid" onclick="document.getElementById('${id}').classList.toggle('open')">
                <span style="font-weight:bold; color:var(--ai-accent)">${req.method}</span>
                <span style="color:${req.status >= 400 ? 'var(--danger)' : 'var(--prod)'}">${req.status}</span>
                <span style="overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${req.url}</span>
                <span style="text-align:right; color:#666;">${req.duration}ms</span>
            </div>
            <div id="${id}" class="ins-net-details">
                <button class="ins-copy-btn" onclick="copyInsEntry(this)" style="opacity:1; top:12px; right:12px;">Copy JSON</button>
                <div style="margin-bottom:10px;"><b style="color:#555">REQUEST:</b><br>${renderJsonHighlight(req.requestBody)}</div>
                <div><b style="color:#555">RESPONSE:</b><br>${renderJsonHighlight(req.responseBody)}</div>
            </div>`;
        list.appendChild(row);
        if (list.parentElement.scrollHeight - list.parentElement.scrollTop < 1000) list.parentElement.scrollTop = list.parentElement.scrollHeight;
    }

    window.addEventListener('message', (e) => {
        if (!e.data || !e.data.type) return;

        if (e.data.type === 'CONDUIT_LOG') {
            const { method, args, time } = e.data;
            const msg = args.map(a => typeof a === 'string' ? a : JSON.stringify(a, null, 2)).join(' ');
            window.inspectorLogData.push({ method, msg, time });
            const container = document.getElementById('ins-console-app');
            if (container) renderLogLine(container, method, msg, time);
        }

        if (e.data.type === 'CONDUIT_NETWORK') {
            const req = e.data.payload;
            window.inspectorNetData.push(req);
            renderNetworkRow('app', req);
        }

        if (e.data.type === 'CONDUIT_NAVIGATE') {
            navigateProxy(e.data.url);
        }
    });

        if(CONFIG.funcUrl) {
            await fetchState();
