    async function processAIResponse() {
        const loadingId = addChatMessage('ai', 'Thinking...', true);
        const contextPayload = [];
        const lastUserMsg = chatHistory[chatHistory.length - 1]?.text || "";

        try {
            if (window.SURGICAL_DEBUG_DATA) {
                contextPayload.push({
                    path: window.SURGICAL_DEBUG_DATA.path,
                    content: b64EncodeUnicode(window.SURGICAL_DEBUG_DATA.content)
                });
                window.SURGICAL_DEBUG_DATA = null;
            } else {
                const checkedBoxes = document.querySelectorAll('#file-list-container .file-check:checked');
                for (const cb of Array.from(checkedBoxes)) {
                    const path = cb.value;
                    let currentContent = "";
                    if (window.CURRENT_FILE_CACHE && window.CURRENT_FILE_CACHE[path]) {
                        currentContent = window.CURRENT_FILE_CACHE[path].content;
                    } else {
                        const fRes = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'preview_file', file_path: path }) });
                        const fData = await fRes.json();
                        currentContent = b64DecodeUnicode(fData.content || "");
                    }

                    // OPTIMIZED: Only push content if the file is 'Dirty' (unsaved changes in IDE)
                    // Otherwise, just send the path and let the Cloud fetch it from GitHub
                    const isDirty = (window.CURRENT_FILE_CACHE && window.CURRENT_FILE_CACHE[path] && window.CURRENT_FILE_CACHE[path].isModified);
                    if (isDirty) {
                        contextPayload.push({ 
                            path: path, 
                            content: b64EncodeUnicode(currentContent), 
                            is_dirty: true 
                        });
                    } else {
                        contextPayload.push({ 
                            path: path, 
                            content: null, 
                            is_dirty: false 
                        });
                    }
                    lastSentFileStates[path] = currentContent;
                }
            }

            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ 
                    action: 'ai_chat', 
                    chat_id: currentChatId,
                    new_message: lastUserMsg,
                    context_files: contextPayload,
                    use_system_prompt: chatUseSystemPrompt,
                    custom_system_prompt: activeCustomPrompt
                })
            });
            const data = await res.json();

            const loadingEl = document.getElementById(loadingId);
            if (loadingEl && loadingEl.parentElement) loadingEl.parentElement.remove();

            if (data.chat_id) currentChatId = data.chat_id;
            let replyText = data.reply || "No response";
            chatHistory.push({ role: 'model', text: replyText });

            renderChatFromHistory();

            const jsonMatch = replyText.match(/```json\s*([\s\S]*?)\s*```/) || replyText.match(/\[\s*\{[\s\S]*\}\s*\]/);
            if (jsonMatch) {
                const jsonStr = jsonMatch[1] || jsonMatch[0];
                try {
                    JSON.parse(jsonStr); 
                    document.getElementById('json-input').value = jsonStr;
                    saveState();
                    const pb = document.querySelectorAll('.nav-item')[1];
                    pb.style.color = "#d946ef";
                    setTimeout(() => pb.style.color = "", 2000);
                } catch(e) { }
            }
        } catch (e) {
            document.getElementById(loadingId).innerText = "Error: " + e.message;
        }
    }

