    async function openSyntaxReport(path, error) {
        const modal = document.getElementById('syntax-report-modal');
        const pathEl = document.getElementById('sr-path');
        const msgEl = document.getElementById('sr-message');
        const codeEl = document.getElementById('sr-code');
        const fixBtn = document.getElementById('btn-auto-fix-wasm');

        pathEl.innerText = path;
        msgEl.innerHTML = `<strong>Line ${error.line}, Col ${error.column || '?'}:</strong> ${error.message}`;
        codeEl.innerText = "Loading context...";
        modal.style.display = 'flex';
        fixBtn.style.display = 'none'; // Hide until we verify deterministic fix

        // Fetch File Content
        try {
            const res = await fetch(CONFIG.funcUrl, { 
                method: 'POST', headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ action: 'preview_file', file_path: path }) 
            });
            const data = await res.json();
            const fullCode = b64DecodeUnicode(data.content || "");

            // Window: 5 lines before and after
            const lines = fullCode.split('\n');
            const start = Math.max(0, error.line - 6);
            const end = Math.min(lines.length, error.line + 5);

            let snippet = "";
            for (let i = start; i < end; i++) {
                const lineNum = i + 1;
                const marker = (lineNum === error.line) ? "> " : "  ";
                snippet += `${marker}${lineNum.toString().padEnd(4)} | ${lines[i]}\n`;
            }

            codeEl.innerText = snippet;

            // Store for fix application
            currentSyntaxContext = { file: path, error: error, code: fullCode, ops: null };

            // Check for Deterministic Fix Availability
            checkDeterministicFix(path, error, fullCode);

        } catch(e) {
            codeEl.innerText = "Failed to load file content: " + e.message;
        }
    }

