    let lastCicdRefresh = 0;

    function switchTab(id, btn) {
        const scrollContainer = document.querySelector('.main-view');
        const activeTab = document.querySelector('.tab-content.active');

        // 1. Save scroll position of current tab
        if (activeTab && scrollContainer) {
            tabScrollPositions[activeTab.id] = scrollContainer.scrollTop;
        }

        // 2. Perform the switch
        document.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
        document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
        document.getElementById(id).classList.add('active');
        if (btn) btn.classList.add('active');

        // 3. Restore scroll position for the target tab
        if (tabScrollPositions[id] !== undefined) {
            // Use a microtask to ensure the display:block layout has calculated
            setTimeout(() => {
                scrollContainer.scrollTo({ top: tabScrollPositions[id], behavior: 'instant' });
            }, 0);
        }

        // Smart Load for CI/CD
        if (id === 'tab-cicd') {
            const now = Date.now();
            const hasActiveRuns = Object.values(runStateCache).some(s => s === 'in_progress' || s === 'queued');
            if (lastCicdRefresh === 0 || (now - lastCicdRefresh > 60000) || hasActiveRuns) {
                loadWorkflows(false);
            }
        }
    }

