    function renderStorageList() {
        const container = document.getElementById('storage-content');

        // Filter
        let list = storageObjects.filter(obj => obj.name.toLowerCase().includes(storageSearchQuery));

        // Folders First Logic (Manual client-side grouping)
        const folders = list.filter(obj => !obj.id);
        const files = list.filter(obj => obj.id);
        const sortedList = [...folders, ...files];

        if(sortedList.length === 0) {
            container.innerHTML = `<div style="padding:40px; text-align:center; color:#444;">${storageObjects.length === 0 ? 'Folder is empty.' : 'No items match filter.'}</div>`;
            return;
        }

        container.innerHTML = sortedList.map((obj) => {
            const realIndex = storageObjects.indexOf(obj);
            const isFolder = !obj.id;
            const icon = isFolder ? 'Ã°ÂÂÂ' : 'Ã°ÂÂÂ';
            return `
                <div class="file-item" style="padding:10px;">
                    <div style="display:flex; align-items:center; gap:10px; flex:1; cursor:pointer; min-width:0;" onclick="${isFolder ? `enterStorageFolder('${obj.name}')` : `openStorageObject('${obj.name}')`}">
