    async function openDiffViewer(id, forcedLeft = null, forcedRight = null) {
        const data = window.OP_CACHE[id];
        if(!data) return;

        const viewer = document.getElementById('diff-viewer');
        const title = document.getElementById('diff-title');

        viewer.classList.add('active');
        toggleFab(false);
        title.innerText = `Comparing: ${data.file.split('/').pop()}`;

        if(!diffLeft) {
            diffLeft = ace.edit("diff-left");
            diffLeft.setTheme("ace/theme/tomorrow_night_bright");
            diffLeft.setReadOnly(true);
            diffLeft.setOption("showPrintMargin", false);

            diffRight = ace.edit("diff-right");
            diffRight.setTheme("ace/theme/tomorrow_night_bright");
            diffRight.setReadOnly(true);
            diffRight.setOption("showPrintMargin", false);

            diffLeft.session.on('changeScrollTop', (top) => diffRight.session.setScrollTop(top));
            diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
            diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
            diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
        }

        diffLeft.setValue("Loading...", -1);
        diffRight.setValue("Loading...", -1);

        try {
            let leftContent = "", rightContent = "";

            if (forcedLeft !== null && forcedRight !== null) {
                leftContent = forcedLeft;
                rightContent = forcedRight;
            } else {
                const rightRef = data.commit_sha || 'HEAD';
                const leftRef = rightRef + '^';

                const fetchFile = async (ref) => {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
                    });
                    const d = await res.json();
                    return d.content ? b64DecodeUnicode(d.content) : '';
                };

                const results = await Promise.all([
                    fetchFile(leftRef).catch(() => ""),
                    fetchFile(rightRef).catch(() => "")
                ]);
                leftContent = results[0];
                rightContent = results[1];
            }

            let mode = "ace/mode/text";
            if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
            else if (data.file.endsWith('.html')) mode = "ace/mode/html";
            else if (data.file.endsWith('.css')) mode = "ace/mode/css";
            else if (data.file.endsWith('.json')) mode = "ace/mode/json";
            else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";

            diffLeft.session.setMode(mode);
            diffLeft.setValue(leftContent, -1);

            diffRight.session.setMode(mode);
            diffRight.setValue(rightContent, -1);

            const Range = ace.require('ace/range').Range;

            // Helper to get Range from String Index
            const getRangeFromText = (session, searchText) => {
                const fullText = session.getValue();
                // 1. Try Exact Match
                let startIdx = fullText.indexOf(searchText);

                // 2. Try Robust Match (Ignoring Line Endings differences)
                if (startIdx === -1) {
                    const clean = (s) => s.replace(/\r\n/g, '\n').trim();
                    startIdx = clean(fullText).indexOf(clean(searchText));
                }

                if (startIdx !== -1) {
                    const linesBefore = fullText.substring(0, startIdx).split('\n');
                    const startRow = linesBefore.length - 1;
                    const startCol = linesBefore[startRow].length;
                    const linesInSearch = searchText.split('\n');
                    const endRow = startRow + linesInSearch.length - 1;
                    const endCol = linesInSearch.length > 1 ? linesInSearch[linesInSearch.length - 1].length : startCol + searchText.length;
                    return new Range(startRow, startCol, endRow, endCol);
                }
                return null;
            };

            const searchRemove = data.op.find_block || data.op.anchor;
            if(searchRemove) {
                const range = getRangeFromText(diffLeft.session, String(searchRemove));
                if(range) {
                    diffLeft.session.addMarker(range, "marker-remove", "fullLine");
                    diffLeft.scrollToLine(range.start.row, true, true, function() {});
                }
            }

            const searchAdd = data.op.replace_with || data.op.content;
            if(searchAdd) {
                const range = getRangeFromText(diffRight.session, String(searchAdd));
                if(range) {
                    diffRight.session.addMarker(range, "marker-add", "fullLine");
                    diffRight.scrollToLine(range.start.row, true, true, function() {});
                }
            }

        } catch(e) {
            diffLeft.setValue("Error: " + e.message, -1);
        }
    }

