                if (btn.isDragging) return;
                const overlay = document.getElementById('inspector-overlay');
                overlay.classList.contains('active') ? closeInspector() : openInspector();
            };
            document.body.appendChild(btn);

            // Draggable Logic
            let x = 0, y = 0, initialX, initialY;
            const onTouchStart = (e) => {
                btn.isDragging = false;
                const touch = e.touches[0];
                initialX = touch.clientX - x;
                initialY = touch.clientY - y;
            };
            const onTouchMove = (e) => {
                btn.isDragging = true;
                const touch = e.touches[0];
                x = touch.clientX - initialX;
                y = touch.clientY - initialY;
                btn.style.transform = `translate(${x}px, ${y}px)`;
            };
            btn.addEventListener('touchstart', onTouchStart);
            btn.addEventListener('touchmove', onTouchMove);
        }

        btn.style.display = CONFIG.floatingConsole ? 'flex' : 'none';
        // Reset position to bottom right default
        btn.style.right = '20px';
        btn.style.bottom = '180px';
    }
