7866 |     function extractTableNames(sql) {
7867 |         if (!sql) return [];
7868 |         const tables = [];
7869 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7870 |         
7871 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7872 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7873 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7874 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7875 | 
7876 |         let match;
7877 |         while ((match = fromRegex.exec(sql)) !== null) {
7878 |             const name = match[1];
7879 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7880 |                 tables.push(name);
7881 |             }
7882 |         }
7883 |         
7884 |         while ((match = metaRegex.exec(sql)) !== null) {
7885 |             const name = match[1];
7886 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7887 |                 tables.push(name);
7888 |             }
7889 |         }
7890 | 
7891 |         return tables;
7892 |     }
7893 | 
7894 |     function convertToCSV(resultObj) {
7895 |         const data = resultObj.data || [];
7896 |         if (!data.length) return '';
7897 |         
7898 |         const tables = extractTableNames(resultObj.sql);
7899 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7900 | 
7901 |         const headers = Object.keys(data[0]);
7902 |         const rows = data.map(row => 
7903 |             headers.map(header => {
7904 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7905 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7906 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7907 |             }).join(',')
7908 |         );
7909 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7910 |     }
