2258 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2259 |     function applyLocalPatch(content, ops) {
2260 |         let lines = content.split('\n');
2261 |         let logs = [];
2262 |         let success = true;
2263 | 
2264 |         if (typeof ops === 'string') {
2265 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2266 |         }
2267 | 
2268 |         ops.forEach(op => {
2269 |             if (op.action === 'comment') return;
2270 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2271 |             
2272 |             if (op.action === 'replace_block') {
2273 |                 // Strategy 1: Exact String Match (Fastest)
2274 |                 const currentStr = lines.join('\n');
2275 |                 if (currentStr.includes(op.find_block)) {
2276 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2277 |                     logs.push('Exact match applied');
2278 |                     return;
2279 |                 }
2280 | 
2281 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2282 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2283 |                 if (searchLines.length === 0) return;
2284 | 
2285 |                 let matchStart = -1;
2286 |                 let matchEnd = -1;
2287 | 
2288 |                 // Scan file lines
2289 |                 for (let i = 0; i < lines.length; i++) {
2290 |                     // If first line matches (ignoring whitespace)
2291 |                     if (lines[i].trim() === searchLines[0]) {
2292 |                         // Check subsequent lines
2293 |                         let allMatch = true;
2294 |                         let fileOffset = 0;
2295 |                         let searchOffset = 1;
2296 |                         
2297 |                         while (searchOffset < searchLines.length) {
2298 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2299 |                             const nextFile = lines[i + fileOffset + 1].trim();
2300 |                             // Skip empty lines in file if they aren't in search block
2301 |                             if (nextFile === '') {
2302 |                                 fileOffset++;
2303 |                                 continue;
2304 |                             }
2305 |                             if (nextFile !== searchLines[searchOffset]) {
2306 |                                 allMatch = false;
2307 |                                 break;
2308 |                             }
2309 |                             fileOffset++;
2310 |                             searchOffset++;
2311 |                         }
2312 | 
2313 |                         if (allMatch) {
2314 |                             matchStart = i;
2315 |                             matchEnd = i + fileOffset;
2316 |                             break;
2317 |                         }
2318 |                     }
2319 |                 }
2320 | 
2321 |                 if (matchStart !== -1) {
2322 |                     // Replace the range of lines
2323 |                     const replacement = op.replace_with.split('\n');
2324 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2325 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2326 |                 } else {
2327 |                     success = false;
2328 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2329 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2330 |                 }
2331 |             }
2332 |         });
2333 |         return { content: lines.join('\n'), success, logs };
2334 |     }
