2357 |                         action: 'propose_syntax_fix', 
2358 |                         code: currentCode, 
2359 |                         error: err 
2360 |                     })
2361 |                 });
2362 |                 const data = await res.json();
2363 |                 const ops = data.operations;
2364 | 
2365 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2366 | 
2367 |                 // 2. Apply Patch Locally
2368 |                 const patchResult = applyLocalPatch(currentCode, ops);
2369 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2370 | 
2371 |                 currentCode = patchResult.content;
2372 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2373 | 
2374 |                 // 3. Re-Validate
2375 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
