2377 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2378 |                 });
2379 |                 const scanData = await scanRes.json();
2380 | 
2381 |                 if (scanData.valid) {
2382 |                     status.innerText = "â Syntax Fixed!";
2383 |                     return true;
2384 |                 } else {
2385 |                     // If errors remain, update list and Prompt user
2386 |                     currentErrors = scanData.errors;
2387 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2388 |                         // Recursively fix the *new* first error (since layout changed)
2389 |                         return await fixNext(0);
2390 |                     } else {
2391 |                         return false;
2392 |                     }
2393 |                 }
2394 | 
2395 |             } catch (e) {
2396 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2397 |                     return await fixNext(index);
2398 |                 } else {
2399 |                     return false;
2400 |                 }
2401 |             }
2402 |         }
2403 | 
2404 |         return await fixNext(0);
