7071 |         if (rollbackTarget) {
7072 |             await fetch(CONFIG.funcUrl, {
7073 |                 method: 'POST', headers: {'Content-Type': 'application/json'},
7074 |                 body: apiBody({ action: 'rollback', ref_sha: rollbackTarget.sha })
